const results = [];

for (const item of items) {
  const f = item.json.fields || {};
  const status = f.field_6 || f.Status || '';
  const postTyp = f.field_2 || f.Post_Typ || '';
  const itemId = item.json.id || item.json.Ausweis || f.id || f.ID;
  const comments = f.field_13 || '';
  const videoFile = f.field_8 || '';

  if (status !== 'Video eingegangen') continue;

  results.push({
    json: {
      _sp_item_id: itemId,
      _post_typ: postTyp || 'Reel',
      _status: status,
      _video_file: videoFile,
      _comments: comments,
      sp_fields: f,
      title: f.Title || f.field_1 || '',
      thema: f.field_1 || f.Title || '',
      content_brief: f.field_3 || '',
      hashtag_thema: f.field_7 || '',
      planned_date: f.Ver_x00f6_ffentlichungsdatum || '',
      planned_time: f.field_5 || ''
    }
  });
}

return results.slice(0, 1);

const f = $json.sp_fields || {};
const comments = $json._comments || '';

function extract(label) {
  const re = new RegExp('- ' + label + ':\\s*([^\\n]+)', 'i');
  const m = comments.match(re);
  return m ? m[1].trim() : '';
}

const videoHinweis = extract('Video-Hinweis');
const tonSprache = extract('Ton enthaelt Sprache');
const personen = extract('Personen sichtbar');
const einverstaendnis = extract('Einverstaendnis vorhanden') || extract('Einverständnis vorhanden');

const PROMPT = `Du bist Social-Media-Texter fuer die Physiotherapiepraxis Physio Fuchs.
Erzeuge fuer ein Instagram Reel/Story-Video ein postingfertiges Textpaket.

Kontext:
- Thema: ${$json.thema}
- Post-Typ: ${$json._post_typ}
- Content-Brief: ${$json.content_brief}
- Hashtag-Thema: ${$json.hashtag_thema}
- Video-Datei: ${$json._video_file}
- Video-Hinweis: ${videoHinweis}
- Ton enthaelt Sprache: ${tonSprache}
- Personen sichtbar: ${personen}
- Einverstaendnis vorhanden: ${einverstaendnis}
- Geplant: ${$json.planned_date} ${$json.planned_time}

Regeln:
- Deutsch.
- Instagram Reel: nahbar, professionell, ruhig, vertrauensbildend.
- Keine Heilversprechen, keine Diagnosen, keine Erfolgsgarantien.
- Keine Patientendaten erfinden.
- Keine Formulierungen wie heilt, garantiert, kuriert, schmerzfrei in X Tagen.
- CTA klar, aber nicht aggressiv.
- Hashtags 10-16 Stueck, passend fuer Physio Fuchs, Physiotherapie, Bewegung, Praxisalltag.
- Falls medizinische Empfehlung: vorsichtig formulieren.

Antworte ausschliesslich als valides JSON:
{
  "hook": "max 80 Zeichen",
  "caption": "2-4 kurze Absaetze, ohne Hashtags",
  "cta": "ein klarer CTA",
  "hashtags": ["#tag1", "#tag2"],
  "story_teaser": "kurzer Story-Teaser",
  "alt_text": "ein Satz fuer Barrierefreiheit",
  "overlay_suggestions": ["max 5 kurze On-Screen-Texte"],
  "quality_check": {
    "heilversprechen": "nein",
    "diagnose": "nein",
    "patientendaten": "nein",
    "cta_vorhanden": "ja"
  }
}`;

return [{
  json: {
    _passthrough: $json,
    model: 'claude-sonnet-4-6',
    max_tokens: 2200,
    messages: [{ role: 'user', content: PROMPT }]
  }
}];

const resp = $json;
const raw = resp.content?.[0]?.text || resp.completion || '';
let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch (e) {
  throw new Error('Claude-Response nicht JSON-parsebar: ' + raw.slice(0, 300));
}
const pt = $('Code: Reel Prompt bauen').first().json._passthrough;
return [{
  json: {
    ...pt,
    hook: parsed.hook || '',
    caption: parsed.caption || '',
    cta: parsed.cta || '',
    hashtags: Array.isArray(parsed.hashtags) ? parsed.hashtags : [],
    story_teaser: parsed.story_teaser || '',
    alt_text: parsed.alt_text || '',
    overlay_suggestions: Array.isArray(parsed.overlay_suggestions) ? parsed.overlay_suggestions : [],
    quality_check: parsed.quality_check || {},
  }
}];

const now = new Date().toISOString().slice(0, 16).replace('T', ' ');
const hashtags = ($json.hashtags || []).join(' ');
const overlay = ($json.overlay_suggestions || []).map(x => '- ' + x).join('\n');
const qc = JSON.stringify($json.quality_check || {});
const log = [
  $json._comments || '',
  `${now} WF-05: Reel-Caption/CTA/Hashtags per KI erzeugt, HWG sauber.`,
  '',
  'WF-05 Textpaket:',
  'HOOK: ' + ($json.hook || ''),
  'CTA: ' + ($json.cta || ''),
  'STORY_TEASER: ' + ($json.story_teaser || ''),
  'ALT_TEXT: ' + ($json.alt_text || ''),
  overlay ? 'OVERLAYS:\n' + overlay : '',
  'QC: ' + qc
].filter(Boolean).join('\n');

return [{
  json: {
    _sp_item_id: $json._sp_item_id,
    payload: {
      field_10: [$json.hook, $json.caption, $json.cta].filter(Boolean).join('\n\n'),
      field_7: hashtags,
      field_6: 'KI-Texte fertig',
      field_13: log
    }
  }
}];

const now = new Date().toISOString().slice(0, 16).replace('T', ' ');
const log = [
  $json._comments || '',
  `${now} WF-05: HWG-FILTER-MATCH -> ${($json._hwg_matches || []).join(', ')}. Texte wurden erzeugt, aber Status Geblockt gesetzt.`
].filter(Boolean).join('\n');
return [{
  json: {
    _sp_item_id: $json._sp_item_id,
    payload: {
      field_10: [$json.hook, $json.caption, $json.cta].filter(Boolean).join('\n\n'),
      field_7: ($json.hashtags || []).join(' '),
      field_6: 'Geblockt',
      field_13: log
    }
  }
}];
